const CSS = `
  *{box-sizing:border-box}body{margin:0}
  .star{position:absolute;border-radius:50%;background:#e8d5a8;animation:tw 3s ease-in-out infinite}
  .ti{display:inline-block;animation:ticker 35s linear infinite;font-family:'Josefin Sans',sans-serif;font-size:10px;color:#6a4a15;letter-spacing:0.2em;text-transform:uppercase}
  .r1{position:absolute;inset:0;border-radius:50%;border:2px solid rgba(212,168,67,0.18);border-top-color:#D4A843;animation:spin 2s linear infinite}
  .r2{position:absolute;inset:13px;border-radius:50%;border:1px solid rgba(212,168,67,0.12);border-top-color:#D4A843;animation:spin 3.2s linear infinite reverse}
  .r3{position:absolute;inset:26px;border-radius:50%;border:1px solid rgba(212,168,67,0.08);border-top-color:#8B6000;animation:spin 4.5s linear infinite}
  @keyframes tw{0%,100%{opacity:.08;transform:scale(1)}50%{opacity:.6;transform:scale(1.6)}}
  @keyframes spin{to{transform:rotate(360deg)}}
  @keyframes slowSpin{to{transform:translateY(-50%) rotate(360deg)}}
  @keyframes floatAnim{0%,100%{transform:translateY(0)}50%{transform:translateY(-11px)}}
  @keyframes pulseGlow{0%,100%{transform:translate(-50%,-50%) scale(1)}50%{transform:translate(-50%,-50%) scale(1.15)}}
  @keyframes ticker{from{transform:translateX(0)}to{transform:translateX(-50%)}}
  button:hover{opacity:.88;transform:translateY(-1px)}
  div[style*="dashed"]:hover{border-color:rgba(212,168,67,0.55)!important;background:rgba(212,168,67,0.05)!important}
  .svcCard:hover{background:rgba(212,168,67,0.06)!important;border-color:rgba(212,168,67,0.3)!important;transform:translateY(-3px)}
  @media(max-width:860px){.HI{grid-template-columns:1fr!important}.HI>div:first-child,.HI>div:last-child{display:none!important}}
`;
